`default_nettype none
`timescale 1ns/1ps

module xtime(
  lhs,
  o
);
  input  wire [7:0] lhs;
  output reg [7:0]  o;
  wire [7:0] shifted;
  always @(shifted or lhs)
  begin
    if (lhs[7]) o = shifted ^ 8'h1b;
    else o = shifted;
  end
  assign shifted = lhs << 1;
endmodule
